mapper.insert:
INSERT INTO MEAL_LOG (
    member_id, meal_date, meal, description,
    totcalorie, meal_time, calories, protein, carbs, fat, image_url
) VALUES (
    #{memberId}, #{mealDate}, #{meal}, #{description},
    #{totCalorie}, #{mealTime}, #{calories}, #{protein}, #{carbs}, #{fat}, #{imageUrl}
)

mapper.select:
SELECT id, member_id, meal_date, meal, description,
       totcalorie, meal_time, calories, protein, carbs, fat, image_url
FROM MEAL_LOG
WHERE member_id = #{memberId}
  AND meal_date = #{mealDate}
ORDER BY meal_time ASC
